$sourcePath = 'C:\Temp\Source'`n$destinationPath = 'C:\Temp\Destination'`n$logFilePath = 'C:\Temp\log.txt'`nfunction Log-Message {`n    param($message)`n    Add-Content -Path $logFilePath -Value ("{0} {1}" -f (Get-Date), $message)`n}`nif (-Not (Test-Path $destinationPath)) {`n    New-Item -ItemType Directory -Path $destinationPath`n}`n$files = Get-ChildItem -Path $sourcePath -File`nforeach ($file in $files) {`n    $destFile = Join-Path -Path $destinationPath -ChildPath $file.Name`n    try {`n        Copy-Item -Path $file.FullName -Destination $destFile -ErrorAction Stop`n        Log-Message "Copied $($file.Name) to $destinationPath"`n    } catch {`n        Log-Message "Failed to copy $($file.Name): $_"`n    }`n}`n$logContent = Get-Content -Path $logFilePath`n$summary = @{} `nforeach ($line in $logContent) {`n    if ($line -like '*Copied*') {`n        $summary['Copied'] += 1`n    } elseif ($line -like '*Failed*') {`n        $summary['Failed'] += 1`n    }`n}`n$summary['Copied'] = if ($summary['Copied'] -eq $null) {0} else {$summary['Copied']}`n$summary['Failed'] = if ($summary['Failed'] -eq $null) {0} else {$summary['Failed']}`n$summary | ConvertTo-Json | Out-File -FilePath (Join-Path -Path $destinationPath -ChildPath 'summary.json')`nStart-Sleep -Seconds 5`nRemove-Item -Path $logFilePath`n
